# Родительский класс (базовый)
class Animal:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def eat(self):
        print(f'{self.name} ест')

    def sleep(self):
        print(f'{self.name} спит')

# Дочерний класс наследует всё от Animal
class Dog(Animal):
    def bark(self):
        print(f'{self.name} говорит: Гав!')

class Cat(Animal):
    def meow(self):
        print(f'{self.name} говорит: Мяу!')

dog = Dog('Рекс', 3)
dog.eat()    # Рекс ест — метод из Animal
dog.sleep()  # Рекс спит — метод из Animal
dog.bark()   # Рекс говорит: Гав! — свой метод

cat = Cat('Мурка', 2)
cat.meow()   # Мурка говорит: Мяу!

class Animal:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def info(self):
        print(f'{self.name}, {self.age} лет')

class Dog(Animal):
    def __init__(self, name, age, breed):
        super().__init__(name, age)  # вызываем __init__ родителя
        self.breed = breed           # добавляем свой атрибут

    def info(self):
        super().info()               # вызываем info() родителя
        print(f'Порода: {self.breed}')  # и добавляем своё

dog = Dog('Рекс', 3, 'Овчарка')
dog.info()
# Рекс, 3 лет
# Порода: Овчарка

class Shape:
    def area(self):
        return 0

    def describe(self):
        print(f'Площадь фигуры: {self.area()}')

class Rectangle(Shape):
    def __init__(self, width, height):
        self.width = width
        self.height = height

    def area(self):           # переопределяем метод родителя
        return self.width * self.height

class Circle(Shape):
    def __init__(self, radius):
        self.radius = radius

    def area(self):           # своя реализация
        return 3.14159 * self.radius ** 2

r = Rectangle(4, 5)
c = Circle(3)

r.describe()   # Площадь фигуры: 20
c.describe()   # Площадь фигуры: 28.27...

# describe() один и тот же, но area() у каждого своя!
for shape in [r, c]:
    print(shape.area())

class Vehicle:
    def __init__(self, brand, speed):
        self.brand = brand
        self.speed = speed

    def move(self):
        print(f'{self.brand} едет со скоростью {self.speed} км/ч')

class Car(Vehicle):
    def __init__(self, brand, speed, doors):
        super().__init__(brand, speed)
        self.doors = doors

    def honk(self):
        print(f'{self.brand}: Бип-бип!')

class ElectricCar(Car):
    def __init__(self, brand, speed, doors, battery):
        super().__init__(brand, speed, doors)
        self.battery = battery

    def charge(self):
        print(f'{self.brand} заряжается. Батарея: {self.battery} кВт·ч')

tesla = ElectricCar('Tesla', 250, 4, 100)
tesla.move()    # из Vehicle
tesla.honk()    # из Car
tesla.charge()  # свой метод

print(ElectricCar.__mro__)  # порядок поиска методов

